mapper.select:
SELECT Row_Number()OVER(ORDER BY TCM.CustomerNo ASC ) as RNUM , TD.Name As CustLvl , TT.Name As CustomerNM , CASE WHEN TCM.CustType = 'CS' THEN 'Customer' ELSE 'Partner' END AS CustType , TCM.BizTypeCode , TCM.BizTypeCode As BizType , TCM.BizItem , Convert(varchar(20), TCM.LastUpdated, 111) AS LastUpdated , TM.Name AS RegUser , TCM.CustomerNo , TCM.CustGRNo , TCM.CustLvl , TCM.TeamID FROM XBOLTAPP.CRM_CUST_MST TCM LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT ON TT.TeamID = TCM.TeamID AND TT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = TCM.RegUserID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = TCM.CustLvl AND TD.LanguageID = #{languageID} AND TD.Category = 'CUSTTP'
AND TCM.CustLvl = #{custLvl}
AND TCM.CustType = #{custType}
AND TT.Name like N'%'+#{searchValue}+'%'

Select TeamID 
From XBOLTAPP.CRM_CUST_MST
Where CustomerNo = #{customerNo}

Select CustomerNo 
From XBOLTAPP.CRM_CUST_MST
Where TeamID = #{custTeamID}

Select CustGRNo 
From XBOLTAPP.CRM_CUST_MST

	
		CustomerNo = #{parentNo}
	
	
		TeamID = #{teamID}

WITH TeamTable AS ( SELECT A.TeamID, A.ParentID FROM XBOLTADM.TB_TEAM A WHERE A.ParentID = #{companyID}
UNION ALL
SELECT B.TeamID, B.ParentID FROM XBOLTADM.TB_TEAM B, TeamTable C WHERE B.ParentID = C.TeamID )
SELECT T1.TeamID FROM TeamTable T1
UNION ALL
SELECT T2.TeamID FROM XBOLTADM.TB_TEAM T2 Where T2.TeamID = #{companyID}
